const elasticsearch = require('elasticsearch');

const client = new elasticsearch.Client({
  node: 'your_elasticsearch_node'
});

async function searchWithScoring(params) {
  const { query, scoreScript } = params;

  const body = {
    query: {
      script_score: {
        script: {
          inline: scoreScript
        },
        query: query
      }
    }
  };

  const response = await client.search({
    index: 'your_index',
    body: body
  });

  return response;
}

